import { StrictMode } from "react";
import { createRoot } from "react-dom/client";

import { App } from "./app/App";
import "./styles.css";

const rootElement = document.getElementById("root");

if (!rootElement) {
  throw new Error("Missing #root element");
}

createRoot(rootElement).render(
  <StrictMode>
    <App />
  </StrictMode>,
);

import { NavLink, Route, Routes } from "react-router-dom";
import { BrowserRouter } from "react-router-dom";

import { AdminPage } from "../features/admin/AdminPage";
import { JobsPage } from "../features/jobs/JobsPage";
import { ReaderPage } from "../features/reader/ReaderPage";
import { useAppStore } from "../state/store";

function formatSocketMessageAge(timestamp: number | null) {
  if (!timestamp) {
    return "no live events yet";
  }
  const seconds = Math.max(0, Math.round((Date.now() - timestamp) / 1000));
  return seconds === 0 ? "just now" : `${seconds}s ago`;
}

function ConnectionBadge() {
  const websocketStatus = useAppStore((state) => state.websocketStatus);
  const lastSocketMessageAt = useAppStore((state) => state.lastSocketMessageAt);
  const lastSocketError = useAppStore((state) => state.lastSocketError);
  const reconnectAttempt = useAppStore((state) => state.reconnectAttempt);
  const isSocketStale = useAppStore((state) => state.isSocketStale);

  const tone =
    websocketStatus === "open" && !isSocketStale
      ? "bg-emerald-100 text-emerald-800"
      : websocketStatus === "connecting" || websocketStatus === "reconnecting"
        ? "bg-amber-100 text-amber-900"
        : websocketStatus === "closed" && !lastSocketError
          ? "bg-stone-200 text-stone-700"
          : "bg-rose-100 text-rose-800";
  const label = websocketStatus === "closed" && !lastSocketError
    ? "idle"
    : isSocketStale
    ? "stale"
    : websocketStatus === "reconnecting"
      ? `reconnecting${reconnectAttempt ? ` #${reconnectAttempt}` : ""}`
      : websocketStatus;

  return (
    <div
      aria-live="polite"
      className={`rounded-3xl px-4 py-3 text-right text-sm ${tone}`}
      title={lastSocketError ?? "Live connection diagnostics"}
    >
      <div className="font-semibold uppercase tracking-[0.2em]">Live {label}</div>
      <div className="text-xs opacity-80">Last message: {formatSocketMessageAge(lastSocketMessageAt)}</div>
      {lastSocketError ? <div className="mt-1 max-w-64 text-xs">{lastSocketError}</div> : null}
    </div>
  );
}

function Shell() {
  return (
    <div className="app-shell px-4 py-6 md:px-8">
      <div className="mx-auto max-w-7xl">
        <header className="panel mb-6 flex flex-col gap-4 rounded-[2rem] px-6 py-5 md:flex-row md:items-center md:justify-between">
          <div>
            <div className="text-sm uppercase tracking-[0.4em] text-stone-600">ReadFlow</div>
            <div className="display-font text-3xl">Batched long-form narration</div>
          </div>
          <div className="flex flex-col gap-3 md:items-end">
            <ConnectionBadge />
            <nav className="flex gap-3">
              {[
                ["/", "Jobs"],
                ["/admin", "Admin"],
              ].map(([to, label]) => (
                <NavLink
                  className={({ isActive }) =>
                    `rounded-full px-4 py-2 text-sm font-semibold ${
                      isActive ? "bg-[var(--accent)] text-white" : "bg-white/70 text-stone-700"
                    }`
                  }
                  end={to === "/"}
                  key={to}
                  to={to}
                >
                  {label}
                </NavLink>
              ))}
            </nav>
          </div>
        </header>

        <Routes>
          <Route element={<JobsPage />} path="/" />
          <Route element={<ReaderPage />} path="/jobs/:jobId" />
          <Route element={<AdminPage />} path="/admin" />
        </Routes>
      </div>
    </div>
  );
}

export function App() {
  return (
    <BrowserRouter>
      <Shell />
    </BrowserRouter>
  );
}

import { create } from "zustand";

import type {
  AdminState,
  JobDetail,
  JobSummary,
  Voice,
  WebSocketStatus,
  WsEnvelope,
} from "../types/api";

interface AppStore {
  jobs: JobSummary[];
  voices: Voice[];
  adminState: AdminState | null;
  websocketStatus: WebSocketStatus;
  lastSocketMessageAt: number | null;
  lastSocketError: string | null;
  reconnectAttempt: number;
  isSocketStale: boolean;
  lastEvent: WsEnvelope | null;
  setJobs: (jobs: JobSummary[]) => void;
  setVoices: (voices: Voice[]) => void;
  setAdminState: (adminState: AdminState) => void;
  setSocketState: (state: {
    status?: AppStore["websocketStatus"];
    lastMessageAt?: number | null;
    error?: string | null;
    reconnectAttempt?: number;
    isStale?: boolean;
  }) => void;
  applyEvent: (event: WsEnvelope) => void;
}

function upsertJob(jobs: JobSummary[], nextJob: JobSummary): JobSummary[] {
  const remaining = jobs.filter((job) => job.id !== nextJob.id);
  return [nextJob, ...remaining];
}

function isAdminConfigPayload(payload: unknown): payload is AdminState["config"] {
  if (typeof payload !== "object" || payload === null) {
    return false;
  }

  const candidate = payload as Record<string, unknown>;
  return (
    typeof candidate.idle_unload_seconds === "number" &&
    typeof candidate.max_prebuffer_seconds === "number" &&
    typeof candidate.target_buffer_seconds === "number" &&
    Array.isArray(candidate.batch_candidates_small_model) &&
    Array.isArray(candidate.batch_candidates_large_model) &&
    typeof candidate.vram_soft_limit_mb === "number" &&
    typeof candidate.vram_hard_limit_mb === "number"
  );
}

function toSummary(job: JobDetail): JobSummary {
  const {
    id,
    title,
    status,
    voice_id,
    model_id,
    is_active_listening,
    total_chunks_emitted,
    total_chunks_completed,
    buffered_seconds,
    completed_seconds,
  } = job;
  return {
    id,
    title,
    status,
    voice_id,
    model_id,
    is_active_listening,
    total_chunks_emitted,
    total_chunks_completed,
    buffered_seconds,
    completed_seconds,
  };
}

export const useAppStore = create<AppStore>((set) => ({
  jobs: [],
  voices: [],
  adminState: null,
  websocketStatus: "connecting",
  lastSocketMessageAt: null,
  lastSocketError: null,
  reconnectAttempt: 0,
  isSocketStale: false,
  lastEvent: null,
  setJobs: (jobs) => set({ jobs }),
  setVoices: (voices) => set({ voices }),
  setAdminState: (adminState) => set({ adminState }),
  setSocketState: ({ status, lastMessageAt, error, reconnectAttempt, isStale }) =>
    set((state) => ({
      websocketStatus: status ?? state.websocketStatus,
      lastSocketMessageAt:
        lastMessageAt === undefined ? state.lastSocketMessageAt : lastMessageAt,
      lastSocketError: error === undefined ? state.lastSocketError : error,
      reconnectAttempt:
        reconnectAttempt === undefined ? state.reconnectAttempt : reconnectAttempt,
      isSocketStale: isStale === undefined ? state.isSocketStale : isStale,
    })),
  applyEvent: (event) =>
    set((state) => {
      if (
        event.type === "job_created" ||
        event.type === "job_updated" ||
        event.type === "job_completed" ||
        event.type === "chunk_ready"
      ) {
        const job = event.payload.job as JobDetail | undefined;
        if (job) {
          return {
            jobs: upsertJob(state.jobs, toSummary(job)),
            lastEvent: event,
          };
        }
      }

      if (event.type === "telemetry" && state.adminState) {
        return {
          adminState: {
            ...state.adminState,
            telemetry: event.payload.telemetry as AdminState["telemetry"],
          },
          lastEvent: event,
        };
      }

      if (event.type === "admin_config_updated" && state.adminState) {
        const nextConfig = isAdminConfigPayload(event.payload)
          ? event.payload
          : state.adminState.config;
        return {
          adminState: {
            ...state.adminState,
            config: nextConfig,
          },
          lastEvent: event,
        };
      }

      if (event.type === "scheduler_state" && state.adminState) {
        return {
          adminState: {
            ...state.adminState,
            scheduler: event.payload as unknown as AdminState["scheduler"],
          },
          lastEvent: event,
        };
      }

      if (event.type === "model_state" && state.adminState) {
        return {
          adminState: {
            ...state.adminState,
            telemetry: {
              ...state.adminState.telemetry,
              model_state: String(event.payload.state ?? state.adminState.telemetry.model_state),
            },
          },
          lastEvent: event,
        };
      }

      return { lastEvent: event };
    }),
}));

import type {
  AdminConfig,
  AdminState,
  JobDetail,
  JobManifest,
  JobSummary,
  Voice,
} from "../types/api";
import { apiPath } from "./transport";

async function request<T>(path: string, init?: RequestInit): Promise<T> {
  const response = await fetch(path, {
    headers: {
      ...(init?.body instanceof FormData ? {} : { "Content-Type": "application/json" }),
      ...init?.headers,
    },
    ...init,
  });
  if (!response.ok) {
    throw new Error(`Request failed: ${response.status}`);
  }
  if (response.status === 204) {
    return undefined as T;
  }
  return (await response.json()) as T;
}

function parseDownloadFilename(contentDisposition: string | null, fallback: string) {
  if (!contentDisposition) {
    return fallback;
  }
  const utf8Match = contentDisposition.match(/filename\*=UTF-8''([^;]+)/i);
  if (utf8Match?.[1]) {
    return decodeURIComponent(utf8Match[1]);
  }
  const quotedMatch = contentDisposition.match(/filename="([^"]+)"/i);
  if (quotedMatch?.[1]) {
    return quotedMatch[1];
  }
  return fallback;
}

export const api = {
  listJobs: () => request<JobSummary[]>(apiPath("/jobs")),
  getJob: (jobId: string) => request<JobDetail>(apiPath(`/jobs/${jobId}`)),
  createJob: (formData: FormData) =>
    request<{ job: JobDetail }>(apiPath("/jobs"), { method: "POST", body: formData }),
  getManifest: (jobId: string) => request<JobManifest>(apiPath(`/jobs/${jobId}/manifest`)),
  activateJob: (jobId: string) =>
    request<JobDetail>(apiPath(`/jobs/${jobId}/activate`), { method: "POST" }),
  pauseJob: (jobId: string) =>
    request<JobDetail>(apiPath(`/jobs/${jobId}/pause`), { method: "POST" }),
  resumeJob: (jobId: string) =>
    request<JobDetail>(apiPath(`/jobs/${jobId}/resume`), { method: "POST" }),
  updateJobVoice: (jobId: string, voiceId: string) =>
    request<JobDetail>(apiPath(`/jobs/${jobId}/voice`), {
      method: "POST",
      body: JSON.stringify({ voice_id: voiceId }),
    }),
  updatePlayback: (jobId: string, currentTimeSeconds: number, isPlaying: boolean) =>
    request<JobDetail>(apiPath(`/jobs/${jobId}/playback`), {
      method: "POST",
      body: JSON.stringify({
        current_time_seconds: currentTimeSeconds,
        is_playing: isPlaying,
      }),
    }),
  downloadJobAudio: async (jobId: string) => {
    const response = await fetch(apiPath(`/jobs/${jobId}/download`));
    if (!response.ok) {
      let detail = `Request failed: ${response.status}`;
      try {
        const payload = (await response.json()) as { detail?: string };
        if (payload.detail) {
          detail = payload.detail;
        }
      } catch {
        // Ignore non-JSON error bodies and keep the status-based fallback.
      }
      throw new Error(detail);
    }
    return {
      blob: await response.blob(),
      filename: parseDownloadFilename(
        response.headers.get("content-disposition"),
        `readflow-job-${jobId}.m4a`,
      ),
    };
  },
  listVoices: () => request<Voice[]>(apiPath("/voices")),
  getAdminState: () => request<AdminState>(apiPath("/admin/state")),
  updateAdminConfig: (config: Partial<AdminConfig>) =>
    request<AdminConfig>(apiPath("/admin/config"), {
      method: "POST",
      body: JSON.stringify(config),
    }),
  warmModel: () => request<{ status: string }>(apiPath("/admin/model/warm"), { method: "POST" }),
  evictModel: () =>
    request<{ status: string }>(apiPath("/admin/model/evict"), { method: "POST" }),
};

export const API_PREFIX = "/api";
export const API_WS_PATH = `${API_PREFIX}/ws`;

export function apiPath(path: string) {
  return `${API_PREFIX}${path}`;
}

export function websocketUrl() {
  const url = new URL(API_WS_PATH, window.location.origin);
  url.protocol = url.protocol === "https:" ? "wss:" : "ws:";
  return url.toString();
}

import { api } from "./api";
import { websocketUrl } from "./transport";
import { useAppStore } from "../state/store";
import type { WsEnvelope } from "../types/api";

const HEARTBEAT_MS = 15_000;
const STALE_AFTER_MS = 30_000;
const RECONNECT_DELAYS_MS = [1_000, 2_000, 5_000] as const;
const RELEASE_GRACE_MS = 250;

function mergeSnapshotJobs(
  existingJobs: ReturnType<typeof useAppStore.getState>["jobs"],
  snapshotJobs: ReturnType<typeof useAppStore.getState>["jobs"],
) {
  const snapshotIds = new Set(snapshotJobs.map((job) => job.id));
  return [...snapshotJobs, ...existingJobs.filter((job) => !snapshotIds.has(job.id))];
}

interface SocketStatePatch {
  status?: ReturnType<typeof useAppStore.getState>["websocketStatus"];
  lastMessageAt?: number | null;
  error?: string | null;
  reconnectAttempt?: number;
  isStale?: boolean;
}

class LiveClient {
  private subscribers = 0;
  private started = false;
  private socket: WebSocket | null = null;
  private reconnectTimer: number | null = null;
  private heartbeatTimer: number | null = null;
  private staleTimer: number | null = null;
  private releaseTimer: number | null = null;
  private reconnectAttempt = 0;
  private hasConnectedOnce = false;
  private intentionalClose = false;

  retain() {
    this.subscribers += 1;
    if (this.releaseTimer !== null) {
      window.clearTimeout(this.releaseTimer);
      this.releaseTimer = null;
    }
    if (this.started) {
      return;
    }
    this.started = true;
    void this.syncSnapshot("Bootstrap sync failed");
    this.connect();
  }

  release() {
    this.subscribers = Math.max(0, this.subscribers - 1);
    if (this.subscribers > 0 || this.releaseTimer !== null) {
      return;
    }
    this.releaseTimer = window.setTimeout(() => {
      this.releaseTimer = null;
      if (this.subscribers === 0) {
        this.stop();
      }
    }, RELEASE_GRACE_MS);
  }

  private store() {
    return useAppStore.getState();
  }

  private setSocketState(state: SocketStatePatch) {
    this.store().setSocketState(state);
  }

  private async syncSnapshot(errorPrefix: string) {
    try {
      const [jobs, voices, adminState] = await Promise.all([
        api.listJobs(),
        api.listVoices(),
        api.getAdminState(),
      ]);
      if (!this.started) {
        return;
      }
      const store = this.store();
      store.setJobs(mergeSnapshotJobs(store.jobs, jobs));
      store.setVoices(voices);
      store.setAdminState(adminState);
    } catch (error) {
      if (!this.started) {
        return;
      }
      this.setSocketState({
        error:
          error instanceof Error ? `${errorPrefix}: ${error.message}` : errorPrefix,
      });
    }
  }

  private clearTimers() {
    if (this.reconnectTimer !== null) {
      window.clearTimeout(this.reconnectTimer);
      this.reconnectTimer = null;
    }
    if (this.heartbeatTimer !== null) {
      window.clearInterval(this.heartbeatTimer);
      this.heartbeatTimer = null;
    }
    if (this.staleTimer !== null) {
      window.clearTimeout(this.staleTimer);
      this.staleTimer = null;
    }
  }

  private markActivity(timestamp = Date.now()) {
    if (!this.started) {
      return;
    }
    this.setSocketState({
      lastMessageAt: timestamp,
      isStale: false,
      error: null,
    });
    if (this.staleTimer !== null) {
      window.clearTimeout(this.staleTimer);
    }
    this.staleTimer = window.setTimeout(() => {
      this.setSocketState({
        isStale: true,
        error: "Live updates are stale. Polling fallback is active.",
      });
    }, STALE_AFTER_MS);
  }

  private scheduleReconnect() {
    if (!this.started || this.reconnectTimer !== null) {
      return;
    }
    this.reconnectAttempt += 1;
    const delay =
      RECONNECT_DELAYS_MS[Math.min(this.reconnectAttempt - 1, RECONNECT_DELAYS_MS.length - 1)];
    this.setSocketState({
      status: "reconnecting",
      reconnectAttempt: this.reconnectAttempt,
      error: `Live updates disconnected. Reconnecting in ${Math.round(delay / 1000)}s…`,
    });
    this.reconnectTimer = window.setTimeout(() => {
      this.reconnectTimer = null;
      this.connect();
    }, delay);
  }

  private connect() {
    if (!this.started) {
      return;
    }
    this.intentionalClose = false;
    this.setSocketState({
      status: this.reconnectAttempt > 0 ? "reconnecting" : "connecting",
      reconnectAttempt: this.reconnectAttempt,
      isStale: false,
    });

    const socket = new WebSocket(websocketUrl());
    this.socket = socket;

    socket.addEventListener("open", () => {
      if (!this.started || this.socket !== socket) {
        return;
      }
      const didReconnect = this.hasConnectedOnce || this.reconnectAttempt > 0;
      this.hasConnectedOnce = true;
      this.reconnectAttempt = 0;
      this.setSocketState({
        status: "open",
        reconnectAttempt: 0,
        error: null,
        isStale: false,
      });
      this.markActivity();
      if (this.heartbeatTimer !== null) {
        window.clearInterval(this.heartbeatTimer);
      }
      this.heartbeatTimer = window.setInterval(() => {
        if (this.socket?.readyState === WebSocket.OPEN) {
          try {
            this.socket.send("ping");
          } catch (error) {
            this.setSocketState({
              status: "error",
              error:
                error instanceof Error ? `Heartbeat failed: ${error.message}` : "Heartbeat failed",
            });
          }
        }
      }, HEARTBEAT_MS);
      if (didReconnect) {
        void this.syncSnapshot("Reconnect sync failed");
      }
    });

    socket.addEventListener("message", (event) => {
      if (!this.started || this.socket !== socket) {
        return;
      }
      this.markActivity();
      if (typeof event.data !== "string") {
        this.setSocketState({
          status: "error",
          error: "Received non-text websocket data",
        });
        return;
      }

      const rawPayload = event.data.trim();
      if (!rawPayload) {
        return;
      }

      let payload: WsEnvelope;
      try {
        payload = JSON.parse(rawPayload) as WsEnvelope;
      } catch {
        this.setSocketState({
          status: "error",
          error: `Received malformed websocket data: ${rawPayload.slice(0, 80)}`,
        });
        return;
      }
      if (payload.type === "pong") {
        return;
      }
      this.store().applyEvent(payload);
    });

    socket.addEventListener("error", () => {
      if (!this.started || this.socket !== socket) {
        return;
      }
      this.setSocketState({
        status: "error",
        error: "WebSocket error detected. Reconnecting…",
      });
    });

    socket.addEventListener("close", () => {
      if (this.socket === socket) {
        this.socket = null;
      }
      if (!this.started || this.intentionalClose) {
        return;
      }
      if (this.heartbeatTimer !== null) {
        window.clearInterval(this.heartbeatTimer);
        this.heartbeatTimer = null;
      }
      this.scheduleReconnect();
    });
  }

  private stop() {
    this.started = false;
    this.hasConnectedOnce = false;
    this.reconnectAttempt = 0;
    if (this.releaseTimer !== null) {
      window.clearTimeout(this.releaseTimer);
      this.releaseTimer = null;
    }
    this.clearTimers();
    this.intentionalClose = true;
    if (this.socket && this.socket.readyState < WebSocket.CLOSING) {
      this.socket.close();
    }
    this.socket = null;
    this.setSocketState({
      status: "closed",
      error: null,
      lastMessageAt: null,
      reconnectAttempt: 0,
      isStale: false,
    });
  }

  resetForTests() {
    this.subscribers = 0;
    this.stop();
  }
}

export const liveClient = new LiveClient();

import { useEffect } from "react";

import { liveClient } from "../lib/live-client";

export function useAppBootstrap(enabled = true) {
  useEffect(() => {
    if (!enabled) {
      return;
    }
    liveClient.retain();
    return () => {
      liveClient.release();
    };
  }, [enabled]);
}

export type JobStatus = "queued" | "rendering" | "paused" | "playing" | "completed" | "failed";
export type ChunkStatus = "planned" | "queued" | "rendering" | "written" | "stale" | "failed";
export type WebSocketStatus = "connecting" | "open" | "reconnecting" | "closed" | "error";

export interface Chunk {
  index: number;
  status: ChunkStatus;
  duration_seconds: number;
  start_seconds: number;
  plan_version: number;
  voice_id: string;
  segment_url: string | null;
}

export interface JobSummary {
  id: string;
  title: string | null;
  status: JobStatus;
  voice_id: string;
  model_id: string;
  is_active_listening: boolean;
  total_chunks_emitted: number;
  total_chunks_completed: number;
  buffered_seconds: number;
  completed_seconds: number;
}

export interface JobDetail extends JobSummary {
  source_kind: string;
  source_text: string;
  plan_version: number;
  chunks: Chunk[];
  failed_reason: string | null;
}

export interface JobManifest {
  mime_type: string;
  init_segment_url: string | null;
  chunks: Chunk[];
}

export interface Voice {
  id: string;
  display_name: string;
  description: string | null;
}

export interface AdminConfig {
  idle_unload_seconds: number;
  max_prebuffer_seconds: number;
  target_buffer_seconds: number;
  batch_candidates_small_model: number[];
  batch_candidates_large_model: number[];
  vram_soft_limit_mb: number;
  vram_hard_limit_mb: number;
}

export interface SchedulerState {
  queue_depth: number;
  batch_candidates: number[];
}

export interface AdminState {
  config: AdminConfig;
  scheduler: SchedulerState;
  telemetry: {
    queue_depth: number;
    model_state: string;
    idle_deadline: number | null;
    oom_count: number;
    recent_batches: Array<{
      batch_size: number;
      duration_seconds: number;
      reserved_vram_mb: number;
      allocated_vram_mb: number;
      at: number;
    }>;
    recent_events: Array<{
      type: string;
      payload: Record<string, unknown>;
      at: number;
    }>;
  };
}

export interface WsEnvelope {
  type:
    | "job_created"
    | "job_updated"
    | "job_completed"
    | "chunk_ready"
    | "scheduler_state"
    | "model_state"
    | "telemetry"
    | "admin_config_updated"
    | "pong";
  payload: Record<string, unknown>;
}

import { useEffect, useMemo, useRef, useState } from "react";
import { Link } from "react-router-dom";

import { api } from "../../lib/api";
import { useAppBootstrap } from "../../hooks/useAppBootstrap";
import { useAppStore } from "../../state/store";
import type { JobSummary } from "../../types/api";
import { JobCreateForm } from "./JobCreateForm";

function StatusBadge({ status }: { status: JobSummary["status"] }) {
  const colors: Record<JobSummary["status"], string> = {
    queued: "bg-stone-200 text-stone-700",
    rendering: "bg-amber-200 text-amber-800",
    paused: "bg-slate-200 text-slate-700",
    playing: "bg-emerald-200 text-emerald-800",
    completed: "bg-teal-200 text-teal-800",
    failed: "bg-rose-200 text-rose-800",
  };

  return <span className={`rounded-full px-3 py-1 text-xs font-semibold ${colors[status]}`}>{status}</span>;
}

export function JobsPage() {
  const jobs = useAppStore((state) => state.jobs);
  const setJobs = useAppStore((state) => state.setJobs);
  const websocketStatus = useAppStore((state) => state.websocketStatus);
  const [error, setError] = useState<string | null>(null);
