      }
      return;
    }
    if (!knownChunks.some((chunk) => chunk.index === playbackAnchorIndex)) {
      setPlaybackAnchorIndex(knownChunks[0]?.index ?? 0);
    }
  }, [knownChunks, playbackAnchorIndex]);

  const anchoredChunks = useMemo(
    () => knownChunks.filter((chunk) => chunk.index >= playbackAnchorIndex),
    [knownChunks, playbackAnchorIndex],
  );

  const contiguousReadyChunks = useMemo(() => {
    const contiguous: Chunk[] = [];
    for (const chunk of anchoredChunks) {
      if (chunk.status !== "written") {
        break;
      }
      contiguous.push(chunk);
    }
    return contiguous;
  }, [anchoredChunks]);

  const firstGapChunk = useMemo(
    () => anchoredChunks.find((chunk) => chunk.status !== "written") ?? null,
    [anchoredChunks],
  );
  const expectedNextChunkIndex = firstGapChunk?.index ?? null;
  const writtenAfterGapIndexes = useMemo(
    () =>
      new Set(
        anchoredChunks
          .filter(
            (chunk) =>
              chunk.index >= (expectedNextChunkIndex ?? Number.POSITIVE_INFINITY) &&
              chunk.status === "written",
          )
          .map((chunk) => chunk.index),
      ),
    [anchoredChunks, expectedNextChunkIndex],
  );
  const missingExpectedIndexes = useMemo(
    () =>
      new Set(
        anchoredChunks
          .filter((chunk) => chunk.status !== "written" && chunk.status !== "failed")
          .map((chunk) => chunk.index),
      ),
    [anchoredChunks],
  );
  const streamManifest = useMemo(
    () => buildStreamManifest(manifest, contiguousReadyChunks),
    [contiguousReadyChunks, manifest],
  );
  const downloadableChunks = useMemo(() => {
    const contiguous: Chunk[] = [];
    for (const chunk of knownChunks) {
      if (chunk.index !== contiguous.length || chunk.status !== "written" || !chunk.segment_url) {
        break;
      }
      contiguous.push(chunk);
    }
    return contiguous;
  }, [knownChunks]);
  const canDownloadRenderedAudio = downloadableChunks.length > 0;
  const isDownloadComplete =
    !!job &&
    isJobTerminal &&
    downloadableChunks.length > 0 &&
    downloadableChunks.length === knownChunks.length;
  const {
    audioRef,
    appendedChunksCount,
    bufferedUntilSeconds,
    currentTimeSeconds,
    diagnostics,
    isActuallyPlaying,
    isAutoplayBlocked,
    isWaitingForData,
    isStreamPrimed,
    lastPlayerError,
    pausePlayback,
    playerState,
    renderedDurationSeconds,
    requestUserGesturePlay,
    seekToSeconds,
  } = useMediaSourcePlayer({
    jobId,
    manifest: streamManifest,
    playbackAnchorIndex,
    playIntent,
    isTerminal: isJobTerminal,
  });

  const activeProgress = useMemo(
    () => deriveActiveChunkProgress(contiguousReadyChunks, currentTimeSeconds),
    [contiguousReadyChunks, currentTimeSeconds],
  );
  const contiguousReadyIndexSet = useMemo(
    () => new Set(contiguousReadyChunks.map((chunk) => chunk.index)),
    [contiguousReadyChunks],
  );
  const streamStartByIndex = useMemo(() => {
    let runningStart = 0;
    const starts = new Map<number, number>();
    for (const chunk of contiguousReadyChunks) {
      starts.set(chunk.index, runningStart);
      runningStart += chunk.duration_seconds;
    }
    return starts;
  }, [contiguousReadyChunks]);

  const timelineSlots = useMemo<TimelineSlot[]>(() => {
    const contiguousReadyIndexes = new Set(contiguousReadyChunks.map((chunk) => chunk.index));
    return knownChunks.map((chunk) => {
      let state: TimelineSlotState;
      if (chunk.status === "failed") {
        state = "failed";
      } else if (activeProgress.activeChunkIndex === chunk.index) {
        state = "playing";
      } else if (activeProgress.playedIndexes.has(chunk.index)) {
        state = "played";
      } else if (chunk.index < playbackAnchorIndex && chunk.status === "written") {
        state = "ready";
      } else if (contiguousReadyIndexes.has(chunk.index)) {
        state = "ready";
      } else if (writtenAfterGapIndexes.has(chunk.index)) {
        state = "ready_after_gap";
      } else if (missingExpectedIndexes.has(chunk.index)) {
        state = "missing_expected";
      } else if (chunk.status === "written") {
        state = "ready";
      } else {
        state = "missing_expected";
      }

      return {
        chunk,
        state,
        fillPercent: activeProgress.fillByIndex.get(chunk.index) ?? (state === "played" ? 100 : 0),
        isAnchor: chunk.index === playbackAnchorIndex,
        visualDurationSeconds:
          chunk.duration_seconds > 0 ? chunk.duration_seconds : TIMELINE_PLACEHOLDER_SECONDS,
      };
    });
  }, [
    activeProgress.activeChunkIndex,
    activeProgress.fillByIndex,
    activeProgress.playedIndexes,
    contiguousReadyChunks,
    knownChunks,
    missingExpectedIndexes,
    playbackAnchorIndex,
    writtenAfterGapIndexes,
  ]);

  const detailSlot = useMemo(() => {
    if (hoveredChunkIndex !== null) {
      return timelineSlots.find((slot) => slot.chunk.index === hoveredChunkIndex) ?? null;
    }
    return timelineSlots.find((slot) => slot.chunk.index === activeProgress.activeChunkIndex) ?? null;
  }, [activeProgress.activeChunkIndex, hoveredChunkIndex, timelineSlots]);

  const writtenChunkCount = knownChunks.filter((chunk) => chunk.status === "written").length;
  const shouldUsePollingFallback =
    !!job && !isTerminalStatus(job.status) && (websocketStatus !== "open" || isSocketStale);
  const liveStatus = describePlayerState(playerState, isAutoplayBlocked);
  const showSpinner =
    playerState === "priming" ||
    playerState === "waiting_for_first_chunk" ||
    playerState === "stalled_waiting_for_next_chunk";
  const primaryButtonLabel =
    playIntent && !isAutoplayBlocked ? "Pause" : isAutoplayBlocked ? "Resume" : "Play";
  const hasReachedTerminalPlaybackEnd =
    isJobTerminal &&
    renderedDurationSeconds > 0 &&
    currentTimeSeconds >= Math.max(0, renderedDurationSeconds - GAP_BUFFERING_EPSILON_SECONDS);

  useEffect(() => {
    manifestRef.current = manifest;
  }, [manifest]);

  const refreshReaderState = useCallback(
    async (reason: string, showLoading = false) => {
      if (!jobId) {
        return;
      }
      if (refreshInFlightRef.current) {
        queuedRefreshReasonRef.current = reason;
        return refreshInFlightRef.current;
      }
      if (showLoading) {
        setLoading(true);
      }
      const requestId = ++refreshRequestIdRef.current;
      const task = Promise.all([api.getJob(jobId), api.getManifest(jobId)])
        .then(([nextJob, nextManifest]) => {
          if (requestId < lastAppliedRequestIdRef.current) {
            return;
          }
          lastAppliedRequestIdRef.current = requestId;
          setJob(nextJob);
          setManifest(nextManifest);
          setError(null);
          setLastRefreshAt(Date.now());
          setLastRefreshReason(reason);
        })
        .catch((loadError) => {
          setError(
            loadError instanceof Error ? loadError.message : "Unable to refresh reader state",
          );
        })
        .finally(async () => {
          refreshInFlightRef.current = null;
          if (showLoading) {
            setLoading(false);
          }
          const queuedReason = queuedRefreshReasonRef.current;
          queuedRefreshReasonRef.current = null;
          if (queuedReason) {
            await refreshReaderState(queuedReason);
          }
        });
      refreshInFlightRef.current = task;
      return task;
    },
    [jobId],
  );

  const syncPlaybackState = useCallback(
    (force = false, isPlayingOverride?: boolean) => {
      if (!job || !audioRef.current || isJobTerminal) {
        return;
      }
      const now = Date.now();
      if (!force && now - lastPlaybackSyncAtRef.current < PLAYBACK_SYNC_INTERVAL_MS) {
        return;
      }
      lastPlaybackSyncAtRef.current = now;
      const isPlaying =
        isPlayingOverride ?? (playIntent && (!audioRef.current.paused || isWaitingForData));
      void api
        .updatePlayback(job.id, audioRef.current.currentTime ?? 0, isPlaying)
        .then(() => setLastPlaybackSyncError(null))
        .catch((syncError) => {
          setLastPlaybackSyncError(
            syncError instanceof Error
              ? `Playback sync failed: ${syncError.message}`
              : "Playback sync failed",
          );
        });
    },
    [audioRef, isJobTerminal, isWaitingForData, job, playIntent],
  );

  useEffect(() => {
    void refreshReaderState("initial", true);
  }, [refreshReaderState]);

  useEffect(() => {
    const payload = lastEvent?.payload as StreamEventPayload | undefined;
    const eventJob = payload?.job;
    if (!lastEvent || !eventJob || eventJob.id !== jobId) {
      return;
    }
    if (
      lastEvent.type !== "job_updated" &&
      lastEvent.type !== "job_completed" &&
      lastEvent.type !== "chunk_ready"
    ) {
      return;
    }

    setJob(eventJob);
    setManifest((previousManifest) => buildManifestFromEvent(eventJob, previousManifest, payload));
    setError(null);
    setLastRefreshAt(Date.now());
    setLastRefreshReason(`ws:${lastEvent.type}`);

    if (
      lastEvent.type === "chunk_ready" &&
      !payload?.mime_type &&
      !payload?.init_segment_url &&
      !manifestRef.current
    ) {
      void refreshReaderState(`ws:${lastEvent.type}:reconcile`);
    }
  }, [jobId, lastEvent, refreshReaderState]);

  useEffect(() => {
    if (!shouldUsePollingFallback) {
      return;
    }
    const timer = window.setInterval(() => {
      void refreshReaderState("poll");
    }, READER_POLL_INTERVAL_MS);
    return () => {
      window.clearInterval(timer);
    };
  }, [refreshReaderState, shouldUsePollingFallback]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio || !job) {
      return;
    }

    const handlePlay = () => {
      if (isJobTerminal) {
        setPlayIntent(true);
      }
      syncPlaybackState(true, true);
    };
    const handlePause = () => {
      if (isJobTerminal) {
        setPlayIntent(false);
        syncPlaybackState(true, false);
        return;
      }
      if (!playIntent) {
        syncPlaybackState(true, false);
      }
    };
    const handleSeek = () => syncPlaybackState(true);
    const handleWaiting = () => syncPlaybackState(true, playIntent);
    const handleEnded = () => {
      if (
        !isJobTerminal &&
        renderedDurationSeconds > 0 &&
        audio.currentTime >= Math.max(0, renderedDurationSeconds - GAP_BUFFERING_EPSILON_SECONDS)
      ) {
        syncPlaybackState(true, true);
        return;
      }
      setPlayIntent(false);
      syncPlaybackState(true, false);
    };
    const handleError = () => syncPlaybackState(true, false);

    audio.addEventListener("play", handlePlay);
    audio.addEventListener("pause", handlePause);
    audio.addEventListener("seeking", handleSeek);
    audio.addEventListener("seeked", handleSeek);
    audio.addEventListener("waiting", handleWaiting);
    audio.addEventListener("ended", handleEnded);
    audio.addEventListener("error", handleError);

    const interval = window.setInterval(() => {
      if (playIntent || isWaitingForData) {
        syncPlaybackState();
      }
    }, PLAYBACK_SYNC_INTERVAL_MS);

    return () => {
      audio.removeEventListener("play", handlePlay);
      audio.removeEventListener("pause", handlePause);
      audio.removeEventListener("seeking", handleSeek);
      audio.removeEventListener("seeked", handleSeek);
      audio.removeEventListener("waiting", handleWaiting);
      audio.removeEventListener("ended", handleEnded);
      audio.removeEventListener("error", handleError);
      window.clearInterval(interval);
    };
  }, [audioRef, isJobTerminal, isWaitingForData, job, playIntent, renderedDurationSeconds, syncPlaybackState]);

  useEffect(() => {
    if (pendingAnchorSeekSeconds === null) {
      return;
    }
    if (!isStreamPrimed || renderedDurationSeconds <= 0) {
      return;
    }
    seekToSeconds(Math.min(pendingAnchorSeekSeconds, renderedDurationSeconds));
    setPendingAnchorSeekSeconds(null);
  }, [isStreamPrimed, pendingAnchorSeekSeconds, renderedDurationSeconds, seekToSeconds]);

  useEffect(() => {
    if (
      !isJobTerminal ||
      !playIntent ||
      isActuallyPlaying ||
      renderedDurationSeconds <= 0 ||
      currentTimeSeconds < Math.max(0, renderedDurationSeconds - GAP_BUFFERING_EPSILON_SECONDS)
    ) {
      return;
    }
    setPlayIntent(false);
  }, [
    currentTimeSeconds,
    isActuallyPlaying,
    isJobTerminal,
    playIntent,
    renderedDurationSeconds,
  ]);

  const handlePlay = async () => {
    if (!job) {
      return;
    }
    if (isJobTerminal) {
      setPlayIntent(true);
      setError(null);
      await requestUserGesturePlay();
      return;
    }
    setPlayIntent(true);
    setError(null);
    try {
      const nextJob = await api.activateJob(job.id);
      setJob(nextJob);
      setManifest((previousManifest) => buildManifestFromEvent(nextJob, previousManifest));
      await requestUserGesturePlay();
    } catch (playError) {
      setPlayIntent(false);
      setError(
        playError instanceof Error ? playError.message : "Unable to activate playback",
      );
    }
  };

  const handlePause = async () => {
    if (!job) {
      return;
    }
    setPlayIntent(false);
    pausePlayback();
    if (isJobTerminal) {
      return;
    }
    try {
      const nextJob = await api.pauseJob(job.id);
      setJob(nextJob);
      setManifest((previousManifest) => buildManifestFromEvent(nextJob, previousManifest));
      syncPlaybackState(true, false);
    } catch (pauseError) {
      setError(
        pauseError instanceof Error ? pauseError.message : "Unable to pause playback",
      );
    }
  };

  const activatePlaybackAtChunk = useCallback(
    async (chunk: Chunk, startOffsetSeconds = 0) => {
      if (!job) {
        return;
      }
      if (isJobTerminal) {
        setPlaybackAnchorIndex(chunk.index);
        setHoveredChunkIndex(chunk.index);
        setPlayIntent(true);
        setPendingAnchorSeekSeconds(startOffsetSeconds);
        setError(null);
        await requestUserGesturePlay();
        return;
      }
      setPlaybackAnchorIndex(chunk.index);
      setHoveredChunkIndex(chunk.index);
      setPlayIntent(true);
      setPendingAnchorSeekSeconds(startOffsetSeconds);
      setError(null);
      try {
        const nextJob = await api.activateJob(job.id);
        setJob(nextJob);
        setManifest((previousManifest) => buildManifestFromEvent(nextJob, previousManifest));
        await requestUserGesturePlay();
      } catch (activationError) {
        setPlayIntent(false);
        setPendingAnchorSeekSeconds(null);
        setError(
          activationError instanceof Error
            ? activationError.message
            : "Unable to activate playback",
        );
      }
    },
    [isJobTerminal, job, requestUserGesturePlay],
  );

  const armPlaybackAtMissingChunk = useCallback(
    async (chunk: Chunk) => {
      if (!job) {
        return;
      }
      setPlaybackAnchorIndex(chunk.index);
      setHoveredChunkIndex(chunk.index);
      setPlayIntent(true);
      setPendingAnchorSeekSeconds(null);
      setError(null);
      try {
        const nextJob = await api.activateJob(job.id);
        setJob(nextJob);
        setManifest((previousManifest) => buildManifestFromEvent(nextJob, previousManifest));
      } catch (activationError) {
        setPlayIntent(false);
        setError(
          activationError instanceof Error
            ? activationError.message
            : "Unable to activate playback",
        );
      }
    },
    [job],
  );

  const seekWithinTimelineSlot = useCallback(
    (slot: TimelineSlot, element: HTMLButtonElement, clientX: number) => {
      if (!contiguousReadyIndexSet.has(slot.chunk.index) || slot.chunk.duration_seconds <= 0) {
        return false;
      }
      const rect = element.getBoundingClientRect();
      if (rect.width <= 0) {
        return false;
      }
      const chunkStartSeconds = streamStartByIndex.get(slot.chunk.index) ?? 0;
      seekToSeconds(
        calculateChunkSeekTargetSeconds(
          clientX,
          { left: rect.left, width: rect.width },
          chunkStartSeconds,
          slot.chunk.duration_seconds,
        ),
      );
      return true;
    },
    [contiguousReadyIndexSet, seekToSeconds, streamStartByIndex],
  );

  const resumeTerminalPlaybackAfterSeek = useCallback(() => {
    if (!isJobTerminal || playIntent || !hasReachedTerminalPlaybackEnd) {
      return;
    }
    setPlayIntent(true);
    setError(null);
    void requestUserGesturePlay();
  }, [
    hasReachedTerminalPlaybackEnd,
    isJobTerminal,
    playIntent,
    requestUserGesturePlay,
  ]);

  const handleTimelinePointerDown = useCallback(
    (event: ReactPointerEvent<HTMLButtonElement>, slot: TimelineSlot) => {
      if (event.button !== 0) {
        return;
      }
      const target = event.currentTarget;
      const didSeek = seekWithinTimelineSlot(slot, target, event.clientX);
      if (!didSeek) {
        return;
      }
      resumeTerminalPlaybackAfterSeek();
      suppressSlotClickIndexRef.current = slot.chunk.index;
      seekingPointerIdRef.current = event.pointerId;
      if (typeof target.setPointerCapture === "function") {
        target.setPointerCapture(event.pointerId);
      }
      event.preventDefault();
    },
    [resumeTerminalPlaybackAfterSeek, seekWithinTimelineSlot],
  );

  const handleTimelinePointerMove = useCallback(
    (event: ReactPointerEvent<HTMLButtonElement>, slot: TimelineSlot) => {
      if (seekingPointerIdRef.current !== event.pointerId) {
        return;
      }
      seekWithinTimelineSlot(slot, event.currentTarget, event.clientX);
    },
    [seekWithinTimelineSlot],
  );

  const clearTimelineSeeking = useCallback((pointerId: number) => {
    if (seekingPointerIdRef.current === pointerId) {
      seekingPointerIdRef.current = null;
    }
  }, []);

  const handleVoiceChange = async (voiceId: string) => {
    if (!job) {
      return;
    }
    try {
      const nextJob = await api.updateJobVoice(job.id, voiceId);
      setJob(nextJob);
      setManifest((previousManifest) => buildManifestFromEvent(nextJob, previousManifest));
      setError(null);
    } catch (voiceError) {
      setError(
        voiceError instanceof Error ? voiceError.message : "Unable to change voice",
      );
    }
  };

  const handleDownload = useCallback(async () => {
    if (!job || downloadableChunks.length === 0) {
      return;
    }

    setDownloadError(null);
    setIsDownloading(true);
    try {
      const { blob, filename } = await api.downloadJobAudio(job.id);
      const downloadUrl = URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = downloadUrl;
      link.download = filename;
      link.click();
      URL.revokeObjectURL(downloadUrl);
    } catch (downloadFailure) {
      setDownloadError(
        downloadFailure instanceof Error
          ? downloadFailure.message
          : "Unable to download rendered audio",
      );
    } finally {
      setIsDownloading(false);
    }
  }, [downloadableChunks.length, job]);

  const handleTimelineSlotClick = async (slot: TimelineSlot) => {
    if (suppressSlotClickIndexRef.current === slot.chunk.index) {
      suppressSlotClickIndexRef.current = null;
      return;
    }

    if (slot.chunk.status === "failed") {
      return;
    }

    if (contiguousReadyIndexSet.has(slot.chunk.index)) {
      seekToSeconds(streamStartByIndex.get(slot.chunk.index) ?? 0);
      resumeTerminalPlaybackAfterSeek();
      return;
    }

    if (slot.chunk.status === "written") {
      await activatePlaybackAtChunk(slot.chunk);
      return;
    }

    await armPlaybackAtMissingChunk(slot.chunk);
  };

  if (loading) {
    return <div className="panel rounded-[2rem] p-8">Loading reader…</div>;
  }

  if (!job) {
    return (
      <div className="panel rounded-[2rem] p-8 text-rose-700">{error ?? "Job not found"}</div>
    );
  }

  return (
    <div className="grid gap-6 xl:grid-cols-[1.3fr_0.9fr]">
      <div className="space-y-6">
        {((!isJobTerminal && (websocketStatus !== "open" || isSocketStale)) ||
          error ||
          lastPlayerError ||
          downloadError) ? (
          <div className="panel rounded-[2rem] border border-amber-200 bg-amber-50/80 p-5 text-sm text-amber-950">
            <div className="mb-2 font-semibold uppercase tracking-[0.2em]">Reader warnings</div>
            <div className="space-y-2">
              {!isJobTerminal && (websocketStatus !== "open" || isSocketStale) ? (
                <div>Live updates degraded, using fallback sync…</div>
              ) : null}
              {error ? <div>{error}</div> : null}
              {lastPlayerError ? <div>{lastPlayerError}</div> : null}
              {lastSocketError ? <div>{lastSocketError}</div> : null}
              {downloadError ? <div>{downloadError}</div> : null}
            </div>
          </div>
        ) : null}

        <div className="panel rounded-[2rem] p-8">
          <div className="mb-4 flex items-center justify-between gap-4">
            <div>
              <p className="text-sm uppercase tracking-[0.3em] text-stone-600">Reader</p>
              <h1 className="display-font text-4xl">{job.title ?? "Untitled job"}</h1>
            </div>
            <div className="rounded-full bg-white/80 px-4 py-2 text-sm text-stone-600">
              {job.status}
            </div>
          </div>
          <div className="rounded-3xl bg-white/60 p-5">
            <p className="whitespace-pre-wrap leading-8 text-stone-800">{job.source_text}</p>
          </div>
        </div>
      </div>

      <div className="space-y-6">
        <div className="panel rounded-[2rem] p-6">
          <audio aria-hidden="true" className="hidden" ref={audioRef} />

          <div
            className={`mb-5 rounded-3xl border px-4 py-3 text-sm ${statusTone(
              playerState,
              isAutoplayBlocked,
              !!(error || lastPlayerError),
            )}`}
          >
            <div className="flex flex-wrap items-center gap-3">
              {showSpinner ? (
                <span
                  aria-hidden="true"
                  className="h-4 w-4 animate-spin rounded-full border-2 border-current border-t-transparent"
                />
              ) : null}
              <span className="font-medium">{liveStatus}</span>
            </div>
          </div>

          <div className="mb-5 flex flex-wrap items-center justify-between gap-4">
            <div className="flex items-center gap-3">
              <button
                className="rounded-full bg-[var(--accent)] px-5 py-3 font-semibold text-white"
                onClick={() => void (playIntent && !isAutoplayBlocked ? handlePause() : handlePlay())}
                type="button"
              >
                {primaryButtonLabel}
              </button>
              <div className="text-sm text-stone-600">
                {formatClock(currentTimeSeconds)} / {formatClock(renderedDurationSeconds)}
              </div>
            </div>
            <div className="flex items-center gap-3">
              <button
                className="rounded-full border border-stone-300 bg-white/80 px-4 py-3 text-sm font-semibold text-stone-700 disabled:cursor-not-allowed disabled:opacity-50"
                disabled={!canDownloadRenderedAudio || isDownloading}
                onClick={() => void handleDownload()}
                type="button"
              >
                {isDownloading
                  ? "Preparing download…"
                  : !canDownloadRenderedAudio
                    ? "Download not ready"
                  : isDownloadComplete
                    ? "Download full audio"
                    : "Download rendered audio so far"}
              </button>
              <div className="text-right text-sm text-stone-600">
                <div>Playable now: {renderedDurationSeconds.toFixed(1)}s</div>
                <div>Buffered: {bufferedUntilSeconds.toFixed(1)}s</div>
              </div>
            </div>
          </div>

          <div className="rounded-[1.75rem] border border-stone-200 bg-stone-200/80 p-2">
            <div className="rounded-[1.25rem] bg-stone-300/70 p-1">
              <div className="flex items-stretch gap-px overflow-hidden rounded-[1rem] bg-white/45">
                {timelineSlots.map((slot) => {
                  const isMissing = slot.state === "missing_expected";
                  const isReadyAfterGap = slot.state === "ready_after_gap";
                  const isPlayingSlot = slot.state === "playing";
                  const isPlayed = slot.state === "played";
                  const isFailed = slot.state === "failed";

                  return (
                    <button
                      aria-label={describeTimelineSlot(slot)}
                      className={`group relative h-12 flex-1 overflow-hidden border-y border-transparent text-left transition first:rounded-l-[0.95rem] last:rounded-r-[0.95rem] ${
                        slot.isAnchor
                          ? "z-10 border-stone-900/60 shadow-[0_0_0_1px_rgba(28,25,23,0.18)]"
                          : ""
                      } ${isFailed ? "cursor-not-allowed" : "cursor-pointer"}`}
                      data-slot-state={slot.state}
                      key={slot.chunk.index}
                    onClick={() => void handleTimelineSlotClick(slot)}
                    onFocus={() => setHoveredChunkIndex(slot.chunk.index)}
                    onMouseEnter={() => setHoveredChunkIndex(slot.chunk.index)}
                    onMouseLeave={() => setHoveredChunkIndex(null)}
                    onPointerDown={(event) => handleTimelinePointerDown(event, slot)}
                    onPointerMove={(event) => handleTimelinePointerMove(event, slot)}
                    onPointerUp={(event) => clearTimelineSeeking(event.pointerId)}
                    onPointerCancel={(event) => clearTimelineSeeking(event.pointerId)}
                    style={{
                      flexGrow: slot.visualDurationSeconds,
                      flexBasis: 0,
                      }}
                      type="button"
                    >
                      <div
                        className={`absolute inset-0 ${
                          isFailed
                            ? "bg-rose-200/90"
                            : isPlayed
                              ? "bg-[var(--accent)]/85"
                              : "bg-stone-400/65"
                        }`}
                      />
                      {isReadyAfterGap ? (
                        <div className="absolute inset-0 bg-stone-400/65" />
                      ) : null}
                      {isMissing ? (
                        <div
                          className="absolute inset-0 opacity-85"
                          style={{
                            backgroundImage:
                              "repeating-linear-gradient(-45deg, rgba(220,38,38,0.28) 0px, rgba(220,38,38,0.28) 6px, transparent 6px, transparent 12px)",
                          }}
                        />
                      ) : null}
                      {!isPlayed && !isFailed && slot.fillPercent > 0 ? (
                        <div
                          className="absolute inset-y-0 left-0 bg-[var(--accent)]/85"
                          style={{ width: `${Math.min(slot.fillPercent, 100)}%` }}
                        />
                      ) : null}
                      {isPlayingSlot ? (
                        <div
                          className="absolute inset-y-0 z-10 w-0.5 bg-stone-950/90"
                          style={{ left: `${Math.min(slot.fillPercent, 100)}%` }}
                        />
                      ) : null}
                      <div className="absolute inset-y-2 right-0 z-10 w-px bg-white/65" />
                      <div className="absolute inset-x-0 top-1 z-10 text-center text-[10px] font-semibold text-stone-900/55 transition group-hover:text-stone-950/80 group-focus-visible:text-stone-950/80">
                        {slot.chunk.index + 1}
                      </div>
                    </button>
                  );
                })}
              </div>
            </div>
          </div>

          <div className="mt-4 grid gap-3 text-sm text-stone-700 md:grid-cols-[1.2fr_0.8fr]">
            <div className="rounded-2xl bg-white/70 p-4">
              <div className="mb-1 font-semibold">
                {detailSlot ? `Chunk ${detailSlot.chunk.index + 1}` : "No chunk selected"}
              </div>
              {detailSlot ? (
                <div className="space-y-1">
                  <div>Status: {chunkStatusText(detailSlot.state)}</div>
                  <div>
                    {detailSlot.chunk.duration_seconds > 0
                      ? `${detailSlot.chunk.duration_seconds.toFixed(1)}s ready`
                      : "Duration not ready yet"}
                  </div>
                  {detailSlot.state === "ready_after_gap" ? (
                    <div>Ready, but blocked until earlier missing chunks arrive.</div>
                  ) : null}
                  {detailSlot.state === "missing_expected" ? (
                    <div>This chunk is expected but has not arrived yet.</div>
                  ) : null}
                </div>
              ) : (
                <div>Press play to arm playback and wait for the first rendered audio chunk.</div>
              )}
            </div>
            <div className="rounded-2xl bg-white/70 p-4">
              <div className="mb-1 font-semibold">Live status</div>
              <div>
                {isJobTerminal
                  ? "Reader is local-only"
                  : websocketStatus === "open" && !isSocketStale
                    ? "WS live"
                    : "Fallback sync"}
              </div>
              <div>
                {writtenChunkCount}/{knownChunks.length} chunks rendered
              </div>
            </div>
          </div>

          <label className="mb-2 mt-5 block text-sm font-semibold uppercase tracking-[0.2em] text-stone-600">
            Voice for future chunks
          </label>
          <select
            className="w-full rounded-2xl border border-stone-300 bg-white/70 px-4 py-3"
            onChange={(event) => void handleVoiceChange(event.target.value)}
            value={job.voice_id}
          >
            {voices.map((voice) => (
              <option key={voice.id} value={voice.id}>
                {voice.display_name}
              </option>
            ))}
          </select>
        </div>

        <details className="panel rounded-[2rem] p-6" open>
          <summary className="cursor-pointer text-lg font-semibold">Live diagnostics</summary>
          <div className="mt-4 grid gap-3 text-sm text-stone-700 md:grid-cols-2">
            <div className="rounded-2xl bg-white/70 p-4">
              Socket: {isJobTerminal ? "idle" : websocketStatus}
              {isSocketStale ? " (stale)" : ""}
            </div>
            <div className="rounded-2xl bg-white/70 p-4">
              Last live event: {formatRelativeTime(lastSocketMessageAt)}
            </div>
            <div className="rounded-2xl bg-white/70 p-4">
              Reader refresh: {formatRelativeTime(lastRefreshAt)} via {lastRefreshReason}
            </div>
            <div className="rounded-2xl bg-white/70 p-4">
              Appended chunks: {appendedChunksCount}
            </div>
            <div className="rounded-2xl bg-white/70 p-4">
              Playback anchor: Chunk {playbackAnchorIndex + 1}
            </div>
            <div className="rounded-2xl bg-white/70 p-4">
              Expected next chunk:{" "}
              {expectedNextChunkIndex === null ? "none" : `Chunk ${expectedNextChunkIndex + 1}`}
            </div>
            <div className="rounded-2xl bg-white/70 p-4">
              Playback intent: {playIntent ? "armed" : "paused"}
            </div>
            <div className="rounded-2xl bg-white/70 p-4">Player state: {playerState}</div>
            <div className="rounded-2xl bg-white/70 p-4">
              Audio: {isActuallyPlaying ? "playing" : diagnostics.paused ? "paused" : "ready"}
            </div>
            <div className="rounded-2xl bg-white/70 p-4">
              Waiting for data: {isWaitingForData ? "yes" : "no"}
            </div>
            <div className="rounded-2xl bg-white/70 p-4">
              Stream primed: {isStreamPrimed ? "yes" : "no"}
            </div>
            <div className="rounded-2xl bg-white/70 p-4">
              Ready after gap: {writtenAfterGapIndexes.size}
            </div>
            <div className="rounded-2xl bg-white/70 p-4">
              Missing expected: {missingExpectedIndexes.size}
            </div>
            <div className="rounded-2xl bg-white/70 p-4">
              Buffered until: {bufferedUntilSeconds.toFixed(1)}s
            </div>
            <div className="rounded-2xl bg-white/70 p-4">
              Current time: {currentTimeSeconds.toFixed(1)}s
            </div>
            <div className="rounded-2xl bg-white/70 p-4">
              Audio ready/network: {diagnostics.readyState}/{diagnostics.networkState}
            </div>
            <div className="rounded-2xl bg-white/70 p-4 md:col-span-2">
              Last transport/player issue:{" "}
              {lastPlayerError ?? lastPlaybackSyncError ?? lastSocketError ?? "none"}
            </div>
          </div>
        </details>

        <div className="panel rounded-[2rem] p-6">
          <h2 className="mb-3 text-lg font-semibold">Chunk status</h2>
          <div className="space-y-2">
            {knownChunks.map((chunk) => (
              <div
                className="flex items-center justify-between rounded-2xl border border-stone-200 bg-white/60 px-4 py-3"
                key={chunk.index}
              >
                <span>Chunk {chunk.index + 1}</span>
                <span className="text-sm text-stone-600">
                  {chunk.status}{" "}
                  {chunk.duration_seconds ? `• ${chunk.duration_seconds.toFixed(1)}s` : ""}
                </span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

export function calculateChunkSeekTargetSeconds(
  clientX: number,
  bounds: { left: number; width: number },
  chunkStartSeconds: number,
  chunkDurationSeconds: number,
) {
  if (bounds.width <= 0 || chunkDurationSeconds <= 0) {
    return chunkStartSeconds;
  }

  const relativeRatio = Math.min(Math.max((clientX - bounds.left) / bounds.width, 0), 1);
  return chunkStartSeconds + chunkDurationSeconds * relativeRatio;
}

import { useCallback, useEffect, useMemo, useRef, useState } from "react";

import type { JobManifest } from "../types/api";

const PLAYABLE_EPSILON_SECONDS = 0.05;

export type PlayerState =
  | "idle"
  | "priming"
  | "waiting_for_first_chunk"
  | "ready_paused"
  | "playing"
  | "stalled_waiting_for_next_chunk"
  | "ended"
  | "error";

interface UseMediaSourcePlayerOptions {
  jobId: string;
  manifest: JobManifest | null;
  playbackAnchorIndex: number;
  playIntent: boolean;
  isTerminal: boolean;
}

interface QueuedChunk {
  index: number;
  url: string;
}

interface AudioDiagnostics {
  paused: boolean;
  readyState: number;
  networkState: number;
}

interface PlaybackSnapshot extends AudioDiagnostics {
  bufferedUntilSeconds: number;
  currentTimeSeconds: number;
}

async function fetchBuffer(url: string): Promise<ArrayBuffer> {
  const response = await fetch(url);
  if (!response.ok) {
    throw new Error(`Failed to fetch media segment: ${response.status}`);
  }
  return response.arrayBuffer();
}

function getBufferedEnd(audio: HTMLAudioElement | null) {
  if (!audio || audio.buffered.length === 0) {
    return 0;
  }
  return audio.buffered.end(audio.buffered.length - 1);
}

function hasBufferedAhead(audio: HTMLAudioElement | null, bufferedUntilSeconds: number) {
  if (!audio) {
    return false;
  }
  return bufferedUntilSeconds > (audio.currentTime ?? 0) + PLAYABLE_EPSILON_SECONDS;
}

function isStoppedAtRenderedBoundary(
  snapshot: PlaybackSnapshot,
  previousSnapshot: PlaybackSnapshot,
  playIntent: boolean,
  isTerminal: boolean,
  renderedDurationSeconds: number,
) {
  if (!playIntent || isTerminal || renderedDurationSeconds <= PLAYABLE_EPSILON_SECONDS) {
    return false;
  }

  const reachedRenderedEnd =
    snapshot.currentTimeSeconds >=
    Math.max(0, renderedDurationSeconds - PLAYABLE_EPSILON_SECONDS);
  const hasFutureBufferedAudio =
    snapshot.bufferedUntilSeconds >
    snapshot.currentTimeSeconds + PLAYABLE_EPSILON_SECONDS;
  const advancedSinceLastSnapshot =
    snapshot.currentTimeSeconds >
    previousSnapshot.currentTimeSeconds + PLAYABLE_EPSILON_SECONDS;

  return reachedRenderedEnd && !hasFutureBufferedAudio && !advancedSinceLastSnapshot;
}

function appendBuffer(sourceBuffer: SourceBuffer, payload: ArrayBuffer) {
  return new Promise<void>((resolve, reject) => {
    const handleUpdateEnd = () => {
      sourceBuffer.removeEventListener("error", handleError);
      resolve();
    };
    const handleError = () => {
      sourceBuffer.removeEventListener("updateend", handleUpdateEnd);
      reject(new Error("SourceBuffer append failed"));
    };
    sourceBuffer.addEventListener("updateend", handleUpdateEnd, { once: true });
    sourceBuffer.addEventListener("error", handleError, { once: true });
    sourceBuffer.appendBuffer(payload);
  });
}

function safePause(audio: HTMLAudioElement) {
  try {
    audio.pause();
  } catch {
    // jsdom does not implement full media playback controls.
  }
}

function safeLoad(audio: HTMLAudioElement) {
  try {
    audio.load();
  } catch {
    // jsdom does not implement full media playback controls.
  }
}

function isAutoplayPolicyError(error: unknown) {
  return error instanceof DOMException && error.name === "NotAllowedError";
}

function readablePlaybackError(error: unknown, fallback: string) {
  if (error instanceof Error && error.message) {
    return error.message;
  }
  return fallback;
}

function clampToBuffered(audio: HTMLAudioElement | null, targetSeconds: number) {
  if (!audio || audio.buffered.length === 0) {
    return 0;
  }

  const clampedTarget = Math.max(0, targetSeconds);
  for (let index = 0; index < audio.buffered.length; index += 1) {
    const start = audio.buffered.start(index);
    const end = audio.buffered.end(index);
    if (clampedTarget < start) {
      return start;
    }
    if (clampedTarget <= end) {
      return clampedTarget;
    }
  }
  return audio.buffered.end(audio.buffered.length - 1);
}

export function useMediaSourcePlayer({
  jobId,
  manifest,
  playbackAnchorIndex,
  playIntent,
  isTerminal,
}: UseMediaSourcePlayerOptions) {
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const sourceBufferRef = useRef<SourceBuffer | null>(null);
  const objectUrlRef = useRef<string | null>(null);
  const activeStreamKeyRef = useRef<string | null>(null);
  const processingQueueRef = useRef(false);
  const initSegmentAppendedRef = useRef(false);
  const initSegmentPendingRef = useRef(false);
  const appendQueueRef = useRef<QueuedChunk[]>([]);
  const appendedChunkIndexesRef = useRef<Set<number>>(new Set());
  const pendingChunkIndexesRef = useRef<Set<number>>(new Set());
  const lastPlaybackSnapshotRef = useRef<PlaybackSnapshot>({
    paused: true,
    readyState: 0,
    networkState: 0,
    bufferedUntilSeconds: 0,
    currentTimeSeconds: 0,
  });
  const playIntentRef = useRef(playIntent);
  const isTerminalRef = useRef(isTerminal);
  const renderedDurationRef = useRef(0);

  const [bufferedUntilSeconds, setBufferedUntilSeconds] = useState(0);
  const [currentTimeSeconds, setCurrentTimeSeconds] = useState(0);
  const [isReady, setIsReady] = useState(false);
  const [isStreamPrimed, setIsStreamPrimed] = useState(false);
  const [isActuallyPlaying, setIsActuallyPlaying] = useState(false);
  const [isWaitingForData, setIsWaitingForData] = useState(false);
  const [lastPlayerError, setLastPlayerError] = useState<string | null>(null);
  const [appendedChunksCount, setAppendedChunksCount] = useState(0);
  const [hasEnded, setHasEnded] = useState(false);
  const [playerState, setPlayerState] = useState<PlayerState>("idle");
  const [isAutoplayBlocked, setIsAutoplayBlocked] = useState(false);
  const [diagnostics, setDiagnostics] = useState<AudioDiagnostics>({
    paused: true,
    readyState: 0,
    networkState: 0,
  });

  const streamKey = manifest ? `${jobId}:${manifest.mime_type}:${playbackAnchorIndex}` : null;
  const mimeType = manifest?.mime_type ?? null;
  const initSegmentUrl = manifest?.init_segment_url ?? null;
  const renderedDurationSeconds = useMemo(
    () =>
      manifest?.chunks.reduce((maxDuration, chunk) => {
        if (chunk.status !== "written") {
          return maxDuration;
        }
        return Math.max(maxDuration, chunk.start_seconds + chunk.duration_seconds);
      }, 0) ?? 0,
    [manifest],
  );

  useEffect(() => {
    playIntentRef.current = playIntent;
  }, [playIntent]);

  useEffect(() => {
    isTerminalRef.current = isTerminal;
  }, [isTerminal]);

  useEffect(() => {
    renderedDurationRef.current = renderedDurationSeconds;
  }, [renderedDurationSeconds]);

  useEffect(() => {
    if (!isTerminal) {
      return;
    }
    setIsWaitingForData(false);
  }, [isTerminal]);

  const updatePlaybackState = useCallback((force = false) => {
    const audio = audioRef.current;
    const nextSnapshot = {
      bufferedUntilSeconds: getBufferedEnd(audio),
      currentTimeSeconds: audio?.currentTime ?? 0,
      paused: audio?.paused ?? true,
      readyState: audio?.readyState ?? 0,
      networkState: audio?.networkState ?? 0,
    } satisfies PlaybackSnapshot;
    const previousSnapshot = lastPlaybackSnapshotRef.current;
    const shouldCommit =
      force ||
      Math.abs(nextSnapshot.currentTimeSeconds - previousSnapshot.currentTimeSeconds) >= 0.05 ||
      Math.abs(nextSnapshot.bufferedUntilSeconds - previousSnapshot.bufferedUntilSeconds) >=
        0.05 ||
      nextSnapshot.paused !== previousSnapshot.paused ||
      nextSnapshot.readyState !== previousSnapshot.readyState ||
      nextSnapshot.networkState !== previousSnapshot.networkState;

    if (!shouldCommit) {
      return;
    }

    lastPlaybackSnapshotRef.current = nextSnapshot;
    setBufferedUntilSeconds(nextSnapshot.bufferedUntilSeconds);
    setCurrentTimeSeconds(nextSnapshot.currentTimeSeconds);
    setDiagnostics({
      paused: nextSnapshot.paused,
      readyState: nextSnapshot.readyState,
      networkState: nextSnapshot.networkState,
    });

    const stoppedAtBoundary = isStoppedAtRenderedBoundary(
      nextSnapshot,
      previousSnapshot,
      playIntentRef.current,
      isTerminalRef.current,
      renderedDurationRef.current,
    );

    if (nextSnapshot.paused) {
      setIsActuallyPlaying(false);
      setIsWaitingForData(stoppedAtBoundary);
      return;
    }

    if (stoppedAtBoundary) {
      setIsActuallyPlaying(false);
      setIsWaitingForData(true);
      return;
    }

    if (
      nextSnapshot.currentTimeSeconds >
      previousSnapshot.currentTimeSeconds + PLAYABLE_EPSILON_SECONDS
    ) {
      setIsActuallyPlaying(true);
      setIsWaitingForData(false);
    }
  }, []);

  const attemptPlay = useCallback(
    async (reason: "auto" | "user") => {
      const audio = audioRef.current;
      if (!audio || !isReady || !isStreamPrimed) {
        return false;
      }
      if (!hasBufferedAhead(audio, bufferedUntilSeconds)) {
        return false;
      }

      try {
        await audio.play();
        setIsAutoplayBlocked(false);
        setLastPlayerError(null);
        return true;
      } catch (error) {
        if (reason === "auto" && isAutoplayPolicyError(error)) {
          setIsAutoplayBlocked(true);
          setLastPlayerError("Playback blocked by browser; press play to resume.");
          return false;
        }
        if (isAutoplayPolicyError(error)) {
          setIsAutoplayBlocked(true);
        }
        setLastPlayerError(
          readablePlaybackError(error, "Unable to resume playback automatically"),
        );
        return false;
      }
    },
    [bufferedUntilSeconds, isReady, isStreamPrimed],
  );

  const processQueue = useCallback(async () => {
    if (processingQueueRef.current || !sourceBufferRef.current || !activeStreamKeyRef.current) {
      return;
    }
    processingQueueRef.current = true;
    try {
      while (appendQueueRef.current.length > 0) {
        const nextChunk = appendQueueRef.current[0];
        const currentStreamKey: string | null = activeStreamKeyRef.current;
        if (!currentStreamKey || currentStreamKey !== streamKey) {
          break;
        }

        try {
          const payload = await fetchBuffer(nextChunk.url);
          if (activeStreamKeyRef.current !== currentStreamKey || !sourceBufferRef.current) {
            break;
          }
          await appendBuffer(sourceBufferRef.current, payload);
          appendQueueRef.current.shift();
          pendingChunkIndexesRef.current.delete(nextChunk.index);
          appendedChunkIndexesRef.current.add(nextChunk.index);
          setAppendedChunksCount(appendedChunkIndexesRef.current.size);
          setLastPlayerError(null);
          setHasEnded(false);
          updatePlaybackState(true);
        } catch (error) {
          pendingChunkIndexesRef.current.delete(nextChunk.index);
          setLastPlayerError(
            readablePlaybackError(error, "Unable to append streamed audio"),
          );
          break;
        }
      }
    } finally {
      processingQueueRef.current = false;
    }
  }, [streamKey, updatePlaybackState]);

  useEffect(() => {
    if (!streamKey || !mimeType || !audioRef.current) {
      return;
    }
    if (!("MediaSource" in window)) {
      setLastPlayerError("MediaSource is not available in this browser");
      setPlayerState("error");
      return;
    }

    let cancelled = false;
    const mediaSource = new MediaSource();
    const objectUrl = URL.createObjectURL(mediaSource);
    const audio = audioRef.current;

    activeStreamKeyRef.current = streamKey;
    sourceBufferRef.current = null;
    objectUrlRef.current = objectUrl;
    initSegmentAppendedRef.current = false;
    initSegmentPendingRef.current = false;
    appendQueueRef.current = [];
    appendedChunkIndexesRef.current = new Set();
    pendingChunkIndexesRef.current = new Set();
    processingQueueRef.current = false;
    lastPlaybackSnapshotRef.current = {
      paused: true,
      readyState: 0,
      networkState: 0,
      bufferedUntilSeconds: 0,
      currentTimeSeconds: 0,
    };
    setBufferedUntilSeconds(0);
    setCurrentTimeSeconds(0);
    setIsReady(false);
    setIsStreamPrimed(false);
    setIsActuallyPlaying(false);
    setIsWaitingForData(false);
    setLastPlayerError(null);
    setAppendedChunksCount(0);
    setHasEnded(false);
    setIsAutoplayBlocked(false);
    setDiagnostics({ paused: true, readyState: 0, networkState: 0 });
    safePause(audio);
    audio.src = objectUrl;

    const handleSourceOpen = async () => {
      try {
        const sourceBuffer = mediaSource.addSourceBuffer(mimeType);
        // Each chunk is packaged as its own fragmented MP4, so we need sequence mode
        // to make MSE place segments back-to-back in append order instead of trusting
        // each fragment's internal timestamps independently.
        sourceBuffer.mode = "sequence";
        sourceBufferRef.current = sourceBuffer;
        if (!cancelled && activeStreamKeyRef.current === streamKey) {
          setIsReady(true);
          setLastPlayerError(null);
          updatePlaybackState(true);
        }
      } catch (error) {
        if (!cancelled) {
          setLastPlayerError(
            readablePlaybackError(error, "Failed to initialize media stream"),
          );
        }
      }
    };

    mediaSource.addEventListener("sourceopen", () => void handleSourceOpen(), { once: true });

    return () => {
      cancelled = true;
      activeStreamKeyRef.current = null;
      sourceBufferRef.current = null;
      appendQueueRef.current = [];
      initSegmentAppendedRef.current = false;
      initSegmentPendingRef.current = false;
      appendedChunkIndexesRef.current.clear();
      pendingChunkIndexesRef.current.clear();
      processingQueueRef.current = false;
      setIsReady(false);
      setIsStreamPrimed(false);
      setHasEnded(false);
      setIsAutoplayBlocked(false);
      safePause(audio);
      audio.removeAttribute("src");
      safeLoad(audio);
      if (objectUrlRef.current) {
        URL.revokeObjectURL(objectUrlRef.current);
        objectUrlRef.current = null;
      }
    };
  }, [mimeType, streamKey, updatePlaybackState]);

  useEffect(() => {
    if (
      !isReady ||
      !streamKey ||
      !initSegmentUrl ||
      !sourceBufferRef.current ||
      initSegmentAppendedRef.current ||
      initSegmentPendingRef.current
    ) {
      return;
    }

    const currentStreamKey = streamKey;
    initSegmentPendingRef.current = true;

    void (async () => {
      try {
        const initBuffer = await fetchBuffer(initSegmentUrl);
        if (activeStreamKeyRef.current !== currentStreamKey || !sourceBufferRef.current) {
          return;
        }
        await appendBuffer(sourceBufferRef.current, initBuffer);
        if (activeStreamKeyRef.current !== currentStreamKey) {
          return;
        }
        initSegmentAppendedRef.current = true;
       setIsStreamPrimed(true);
        setLastPlayerError(null);
        updatePlaybackState(true);
        void processQueue();
      } catch (error) {
        setLastPlayerError(
          readablePlaybackError(error, "Failed to initialize media stream"),
        );
      } finally {
        initSegmentPendingRef.current = false;
      }
    })();
  }, [initSegmentUrl, isReady, processQueue, streamKey, updatePlaybackState]);

  useEffect(() => {
    if (!manifest || !isReady || !isStreamPrimed || activeStreamKeyRef.current !== streamKey) {
      return;
    }
    const missingChunks = manifest.chunks
      .filter(
        (chunk) =>
          chunk.status === "written" &&
          !!chunk.segment_url &&
          !appendedChunkIndexesRef.current.has(chunk.index) &&
          !pendingChunkIndexesRef.current.has(chunk.index),
      )
      .sort((left, right) => left.index - right.index);

    if (missingChunks.length === 0) {
      return;
    }

    for (const chunk of missingChunks) {
      if (!chunk.segment_url) {
        continue;
      }
      pendingChunkIndexesRef.current.add(chunk.index);
      appendQueueRef.current.push({ index: chunk.index, url: chunk.segment_url });
    }
    appendQueueRef.current.sort((left, right) => left.index - right.index);
    void processQueue();
  }, [isReady, isStreamPrimed, manifest, processQueue, streamKey]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) {
      return;
    }

    const handlePlay = () => {
      setIsActuallyPlaying(true);
      setIsWaitingForData(false);
      setIsAutoplayBlocked(false);
      setLastPlayerError(null);
      setHasEnded(false);
      updatePlaybackState(true);
    };
    const handlePause = () => {
      setIsActuallyPlaying(false);
      updatePlaybackState(true);
    };
    const handleWaiting = () => {
      setIsWaitingForData(true);
      setIsActuallyPlaying(false);
      updatePlaybackState(true);
    };
    const handleProgress = () => {
      updatePlaybackState(true);
    };
    const handleTimeUpdate = () => {
      updatePlaybackState(true);
    };
    const handleSeeking = () => {
      updatePlaybackState(true);
    };
    const handleEnded = () => {
      setHasEnded(isTerminal);
      setIsActuallyPlaying(false);
      updatePlaybackState(true);
    };
    const handlePlaying = () => {
      setHasEnded(false);
      setIsActuallyPlaying(true);
      setIsWaitingForData(false);
      setIsAutoplayBlocked(false);
      setLastPlayerError(null);
      updatePlaybackState(true);
    };
    const handleError = () => {
      setIsActuallyPlaying(false);
      setLastPlayerError("Audio playback failed");
      updatePlaybackState(true);
    };

    audio.addEventListener("play", handlePlay);
    audio.addEventListener("pause", handlePause);
    audio.addEventListener("waiting", handleWaiting);
    audio.addEventListener("progress", handleProgress);
    audio.addEventListener("timeupdate", handleTimeUpdate);
    audio.addEventListener("seeking", handleSeeking);
    audio.addEventListener("seeked", handleProgress);
    audio.addEventListener("ended", handleEnded);
    audio.addEventListener("playing", handlePlaying);
    audio.addEventListener("error", handleError);

    return () => {
      audio.removeEventListener("play", handlePlay);
      audio.removeEventListener("pause", handlePause);
      audio.removeEventListener("waiting", handleWaiting);
      audio.removeEventListener("progress", handleProgress);
      audio.removeEventListener("timeupdate", handleTimeUpdate);
      audio.removeEventListener("seeking", handleSeeking);
      audio.removeEventListener("seeked", handleProgress);
      audio.removeEventListener("ended", handleEnded);
      audio.removeEventListener("playing", handlePlaying);
      audio.removeEventListener("error", handleError);
    };
  }, [isTerminal, updatePlaybackState]);

  useEffect(() => {
    if (!playIntent && !isActuallyPlaying && !isWaitingForData) {
      return;
    }

    let frameId = 0;
    const tick = () => {
      updatePlaybackState();
      frameId = window.requestAnimationFrame(tick);
    };

    frameId = window.requestAnimationFrame(tick);
    return () => {
      window.cancelAnimationFrame(frameId);
    };
  }, [isActuallyPlaying, isWaitingForData, playIntent, updatePlaybackState]);

  useEffect(() => {
    if (!playIntent || isAutoplayBlocked) {
      return;
    }
    const audio = audioRef.current;
    if (!audio || !isReady || !isStreamPrimed) {
      return;
    }
    if (!hasBufferedAhead(audio, bufferedUntilSeconds)) {
      return;
    }
    if (!audio.paused && !isWaitingForData) {
      return;
    }
    void attemptPlay("auto");
  }, [
    attemptPlay,
    bufferedUntilSeconds,
    isAutoplayBlocked,
    isReady,
    isStreamPrimed,
    isWaitingForData,
    playIntent,
  ]);

  useEffect(() => {
    if (lastPlayerError) {
      setPlayerState("error");
      return;
    }
    if (
      isTerminal &&
      renderedDurationSeconds > PLAYABLE_EPSILON_SECONDS &&
      currentTimeSeconds >= Math.max(0, renderedDurationSeconds - PLAYABLE_EPSILON_SECONDS) &&
      !isActuallyPlaying
    ) {
      setPlayerState("ended");
      return;
    }
    if (playIntent) {
      if (!isStreamPrimed || renderedDurationSeconds <= PLAYABLE_EPSILON_SECONDS) {
        setPlayerState("waiting_for_first_chunk");
        return;
      }
      const stalledAtRenderedBoundary = isStoppedAtRenderedBoundary(
        {
          bufferedUntilSeconds,
          currentTimeSeconds,
          paused: diagnostics.paused,
          readyState: diagnostics.readyState,
          networkState: diagnostics.networkState,
        },
        lastPlaybackSnapshotRef.current,
        true,
        isTerminal,
        renderedDurationSeconds,
      );
      if (isWaitingForData || stalledAtRenderedBoundary) {
        if (!isWaitingForData && stalledAtRenderedBoundary) {
          setIsWaitingForData(true);
        }
        setPlayerState(
          currentTimeSeconds <= PLAYABLE_EPSILON_SECONDS
            ? "waiting_for_first_chunk"
            : "stalled_waiting_for_next_chunk",
        );
        return;
      }
      if (isActuallyPlaying) {
        setPlayerState("playing");
        return;
      }
      if (bufferedUntilSeconds <= currentTimeSeconds + PLAYABLE_EPSILON_SECONDS) {
        setPlayerState("ready_paused");
        return;
      }
      setPlayerState("ready_paused");
      return;
    }
    if (hasEnded && isTerminal) {
      setPlayerState("ended");
      return;
    }
    if (streamKey && !isStreamPrimed) {
      setPlayerState("priming");
      return;
    }
    if (isStreamPrimed && renderedDurationSeconds > PLAYABLE_EPSILON_SECONDS) {
      setPlayerState("ready_paused");
      return;
    }
    setPlayerState("idle");
  }, [
    bufferedUntilSeconds,
    currentTimeSeconds,
    diagnostics.networkState,
    diagnostics.paused,
    diagnostics.readyState,
    hasEnded,
    isActuallyPlaying,
    isStreamPrimed,
    isTerminal,
    isWaitingForData,
    lastPlayerError,
    playIntent,
    renderedDurationSeconds,
    streamKey,
  ]);

  const requestUserGesturePlay = useCallback(async () => {
    const played = await attemptPlay("user");
    if (!played) {
      updatePlaybackState(true);
    }
    return played;
  }, [attemptPlay, updatePlaybackState]);

  const pausePlayback = useCallback(() => {
    audioRef.current?.pause();
    updatePlaybackState(true);
  }, [updatePlaybackState]);

  const seekToSeconds = useCallback(
    (targetSeconds: number) => {
      const audio = audioRef.current;
      if (!audio) {
        return 0;
      }
      const cappedTarget = Math.min(targetSeconds, renderedDurationSeconds);
      const clampedTarget = clampToBuffered(audio, cappedTarget);
      audio.currentTime = clampedTarget;
      setHasEnded(false);
      updatePlaybackState(true);
      return clampedTarget;
    },
    [renderedDurationSeconds, updatePlaybackState],
  );

  return {
    audioRef,
    appendedChunksCount,
    bufferedUntilSeconds,
    currentTimeSeconds,
    diagnostics,
    isActuallyPlaying,
    isAutoplayBlocked,
    isReady,
    isStreamPrimed,
    isWaitingForData,
    lastPlayerError,
    pausePlayback,
    playerState,
    renderedDurationSeconds,
    requestUserGesturePlay,
    seekToSeconds,
  };
}

