## Risk Mitigation

### Breaking changes are scoped

The only breaking change is the store's `jobs` shape (array → Record). This affects:
- `src/features/jobs/JobsPage.tsx` — iterate `Object.values(state.jobs)` instead of `state.jobs`
- `src/features/reader/ReaderPage.tsx` — same change
- `src/lib/live-client.ts` → `snapshot-sync.ts` — use `Object.values` for merge

All other changes are additive (new files). The `api.ts` interface is unchanged (same functions).

### No hacky workarounds

- No more `as` type assertions — discriminated union + zod validation replaces them.
- No more prototype mutation in tests — proper mock isolation.
- No more singleton classes with manual lifecycle — React hooks manage lifecycle through effects.
- No more 700-line components — clear separation of concerns.

### Auth is opt-in

Every auth change uses conditional logic:
- `api.ts`: `getToken()` returns `null` → no auth header (current behavior)
- `useLiveEvents`: `authToken` is `null` → connect without token (current behavior)
- `ProtectedRoute`: `isAuthenticated` is `false` → show login page (new page)

The app functions identically without auth configured.

import type { AdminConfig, JobDetail, SchedulerState } from "./api";

export interface JobPayload {
  job: JobDetail;
}

export interface ChunkReadyPayload extends JobPayload {
  chunk_index: number;
  mime_type?: string;
  init_segment_url?: string | null;
}

export interface TelemetryPayload {
  telemetry: AdminStateTelemetry;
}

export interface ModelStatePayload {
  state: string;
}

export type AdminStateTelemetry = NonNullable<AdminState["telemetry"]>;

export interface AdminState {
  config: AdminConfig;
  scheduler: SchedulerState;
  telemetry: {
    queue_depth: number;
    model_state: string;
    idle_deadline: number | null;
    oom_count: number;
    recent_batches: Array<{
      batch_size: number;
      duration_seconds: number;
      reserved_vram_mb: number;
      allocated_vram_mb: number;
      at: number;
    }>;
    recent_events: Array<{
      type: string;
      payload: Record<string, unknown>;
      at: number;
    }>;
  } | null;
}

export type WsEnvelope =
  | { type: "job_created"; payload: JobPayload }
  | { type: "job_updated"; payload: JobPayload }
  | { type: "job_completed"; payload: JobPayload }
  | { type: "chunk_ready"; payload: ChunkReadyPayload }
  | { type: "scheduler_state"; payload: SchedulerState }
  | { type: "model_state"; payload: ModelStatePayload }
  | { type: "telemetry"; payload: TelemetryPayload }
  | { type: "admin_config_updated"; payload: AdminConfig }
  | { type: "pong"; payload: null };

export type JobStatus = "queued" | "rendering" | "paused" | "playing" | "completed" | "failed";
export type ChunkStatus = "planned" | "queued" | "rendering" | "written" | "stale" | "failed";

export interface Chunk {
  index: number;
  status: ChunkStatus;
  duration_seconds: number;
  start_seconds: number;
  plan_version: number;
  voice_id: string;
  segment_url: string | null;
}

export interface JobSummary {
  id: string;
  title: string | null;
  status: JobStatus;
  voice_id: string;
  model_id: string;
  is_active_listening: boolean;
  total_chunks_emitted: number;
  total_chunks_completed: number;
  buffered_seconds: number;
  completed_seconds: number;
}

export interface JobDetail extends JobSummary {
  source_kind: string;
  source_text: string;
  plan_version: number;
  chunks: Chunk[];
  failed_reason: string | null;
}

export interface JobManifest {
  mime_type: string;
  init_segment_url: string | null;
  chunks: Chunk[];
}

export interface Voice {
  id: string;
  display_name: string;
  description: string | null;
}

export interface AdminConfig {
  idle_unload_seconds: number;
  max_prebuffer_seconds: number;
  target_buffer_seconds: number;
  batch_candidates_small_model: number[];
  batch_candidates_large_model: number[];
  vram_soft_limit_mb: number;
  vram_hard_limit_mb: number;
}

export interface SchedulerState {
  queue_depth: number;
  batch_candidates: number[];
}

import type { AdminConfig, JobDetail, SchedulerState } from "./api";

export interface JobPayload {
  job: JobDetail;
}

export interface ChunkReadyPayload extends JobPayload {
  chunk_index: number;
  mime_type?: string;
  init_segment_url?: string | null;
}

export interface TelemetryPayload {
  telemetry: TelemetrySnapshot;
}

export interface ModelStatePayload {
  state: string;
}

export type TelemetrySnapshot = {
  queue_depth: number;
  model_state: string;
  idle_deadline: number | null;
  oom_count: number;
  recent_batches: Array<{
    batch_size: number;
    duration_seconds: number;
    reserved_vram_mb: number;
    allocated_vram_mb: number;
    at: number;
  }>;
  recent_events: Array<{
    type: string;
    payload: Record<string, unknown>;
    at: number;
  }>;
};

export type WsEnvelope =
  | { type: "job_created"; payload: JobPayload }
  | { type: "job_updated"; payload: JobPayload }
  | { type: "job_completed"; payload: JobPayload }
  | { type: "chunk_ready"; payload: ChunkReadyPayload }
  | { type: "scheduler_state"; payload: SchedulerState }
  | { type: "model_state"; payload: ModelStatePayload }
  | { type: "telemetry"; payload: TelemetryPayload }
  | { type: "admin_config_updated"; payload: AdminConfig }
  | { type: "pong"; payload: null };

export type PlayerState =
  | "idle"
  | "priming"
  | "waiting_for_first_chunk"
  | "ready_paused"
  | "playing"
  | "stalled_waiting_for_next_chunk"
  | "ended"
  | "error";

export type WebSocketStatus = "connecting" | "open" | "reconnecting" | "closed" | "error";

export interface AudioDiagnostics {
  paused: boolean;
  readyState: number;
  networkState: number;
}

import { create } from "zustand";

import type { AdminConfig, JobDetail, JobSummary, Voice } from "../types/api";
import type {
  AdminStateTelemetry,
  SchedulerState,
  WsEnvelope,
} from "../types/events";

interface AppStore {
  jobs: Record<string, JobSummary>;
  voices: Voice[];
  adminState: AdminState | null;
  websocketStatus: "connecting" | "open" | "reconnecting" | "closed" | "error";
  lastSocketMessageAt: number | null;
  lastSocketError: string | null;
  reconnectAttempt: number;
  isSocketStale: boolean;
  lastEvent: WsEnvelope | null;
  setJobs: (jobs: Record<string, JobSummary>) => void;
  setVoices: (voices: Voice[]) => void;
  setAdminState: (adminState: AdminState) => void;
  setSocketState: (state: {
    status?: AppStore["websocketStatus"];
    lastMessageAt?: number | null;
    error?: string | null;
    reconnectAttempt?: number;
    isStale?: boolean;
  }) => void;
  applyEvent: (event: WsEnvelope) => void;
}

interface AdminState {
  config: AdminConfig;
  scheduler: SchedulerState;
  telemetry: AdminStateTelemetry;
}

function upsertJob(
  jobs: Record<string, JobSummary>,
  nextJob: JobSummary,
): Record<string, JobSummary> {
  return { ...jobs, [nextJob.id]: toSummary(nextJob) };
}

function toSummary(job: JobDetail): JobSummary {
  return {
    id: job.id,
    title: job.title,
    status: job.status,
    voice_id: job.voice_id,
    model_id: job.model_id,
    is_active_listening: job.is_active_listening,
    total_chunks_emitted: job.total_chunks_emitted,
    total_chunks_completed: job.total_chunks_completed,
    buffered_seconds: job.buffered_seconds,
    completed_seconds: job.completed_seconds,
  };
}

export const useAppStore = create<AppStore>((set) => ({
  jobs: {},
  voices: [],
  adminState: null,
  websocketStatus: "connecting",
  lastSocketMessageAt: null,
  lastSocketError: null,
  reconnectAttempt: 0,
  isSocketStale: false,
  lastEvent: null,
  setJobs: (jobs) => set({ jobs }),
  setVoices: (voices) => set({ voices }),
  setAdminState: (adminState) => set({ adminState }),
  setSocketState: ({ status, lastMessageAt, error, reconnectAttempt, isStale }) =>
    set((state) => ({
      websocketStatus: status ?? state.websocketStatus,
      lastSocketMessageAt:
        lastMessageAt === undefined ? state.lastSocketMessageAt : lastMessageAt,
      lastSocketError: error === undefined ? state.lastSocketError : error,
      reconnectAttempt:
        reconnectAttempt === undefined ? state.reconnectAttempt : reconnectAttempt,
      isSocketStale: isStale === undefined ? state.isSocketStale : isStale,
    })),
  applyEvent: (event) =>
    set((state) => {
      if (
        event.type === "job_created" ||
        event.type === "job_updated" ||
        event.type === "job_completed" ||
        event.type === "chunk_ready"
      ) {
        const job = event.payload.job;
        if (job) {
          return {
            jobs: upsertJob(state.jobs, job),
            lastEvent: event,
          };
        }
      }

      if (event.type === "telemetry" && state.adminState) {
        return {
          adminState: {
            ...state.adminState,
            telemetry: event.payload.telemetry,
          },
          lastEvent: event,
        };
      }

      if (event.type === "admin_config_updated" && state.adminState) {
        return {
          adminState: {
            ...state.adminState,
            config: event.payload,
          },
          lastEvent: event,
        };
      }

      if (event.type === "scheduler_state" && state.adminState) {
        return {
          adminState: {
            ...state.adminState,
            scheduler: event.payload,
          },
          lastEvent: event,
        };
      }

      if (event.type === "model_state" && state.adminState) {
        return {
          adminState: {
            ...state.adminState,
            telemetry: {
              ...state.adminState.telemetry,
              model_state: event.payload.state ?? state.adminState.telemetry.model_state,
            },
          },
          lastEvent: event,
        };
      }

      return { lastEvent: event };
    }),
}));

import { api } from "./api";
import { websocketUrl } from "./transport";
import { useAppStore } from "../state/store";
import type { JobSummary, WsEnvelope } from "../types/api";

const HEARTBEAT_MS = 15_000;
const STALE_AFTER_MS = 30_000;
const RECONNECT_DELAYS_MS = [1_000, 2_000, 5_000] as const;
const RELEASE_GRACE_MS = 250;

function mergeSnapshotJobs(
  existingJobs: Record<string, JobSummary>,
  snapshotJobs: JobSummary[],
): Record<string, JobSummary> {
  const merged: Record<string, JobSummary> = { ...existingJobs };
  for (const job of snapshotJobs) {
    merged[job.id] = job;
  }
  return merged;
}

interface SocketStatePatch {
  status?: ReturnType<typeof useAppStore.getState>["websocketStatus"];
  lastMessageAt?: number | null;
  error?: string | null;
  reconnectAttempt?: number;
  isStale?: boolean;
}

class LiveClient {
  private subscribers = 0;
  private started = false;
  private socket: WebSocket | null = null;
  private reconnectTimer: number | null = null;
  private heartbeatTimer: number | null = null;
  private staleTimer: number | null = null;
  private releaseTimer: number | null = null;
  private reconnectAttempt = 0;
  private hasConnectedOnce = false;
  private intentionalClose = false;

  retain() {
    this.subscribers += 1;
    if (this.releaseTimer !== null) {
      window.clearTimeout(this.releaseTimer);
      this.releaseTimer = null;
    }
    if (this.started) {
      return;
    }
    this.started = true;
    void this.syncSnapshot("Bootstrap sync failed");
    this.connect();
  }

  release() {
    this.subscribers = Math.max(0, this.subscribers - 1);
    if (this.subscribers > 0 || this.releaseTimer !== null) {
      return;
    }
    this.releaseTimer = window.setTimeout(() => {
      this.releaseTimer = null;
      if (this.subscribers === 0) {
        this.stop();
      }
    }, RELEASE_GRACE_MS);
  }

  private store() {
    return useAppStore.getState();
  }

  private setSocketState(state: SocketStatePatch) {
    this.store().setSocketState(state);
  }

  private async syncSnapshot(errorPrefix: string) {
    try {
      const [jobs, voices, adminState] = await Promise.all([
        api.listJobs(),
        api.listVoices(),
        api.getAdminState(),
      ]);
      if (!this.started) {
        return;
      }
      const store = this.store();
      store.setJobs(mergeSnapshotJobs(store.jobs, jobs));
      store.setVoices(voices);
      store.setAdminState(adminState);
    } catch (error) {
      if (!this.started) {
        return;
      }
      this.setSocketState({
        error:
          error instanceof Error ? `${errorPrefix}: ${error.message}` : errorPrefix,
      });
    }
  }

  private clearTimers() {
    if (this.reconnectTimer !== null) {
      window.clearTimeout(this.reconnectTimer);
      this.reconnectTimer = null;
    }
    if (this.heartbeatTimer !== null) {
      window.clearInterval(this.heartbeatTimer);
      this.heartbeatTimer = null;
    }
    if (this.staleTimer !== null) {
      window.clearTimeout(this.staleTimer);
      this.staleTimer = null;
    }
  }

  private markActivity(timestamp = Date.now()) {
    if (!this.started) {
      return;
    }
    this.setSocketState({
      lastMessageAt: timestamp,
      isStale: false,
      error: null,
    });
    if (this.staleTimer !== null) {
      window.clearTimeout(this.staleTimer);
    }
    this.staleTimer = window.setTimeout(() => {
      this.setSocketState({
        isStale: true,
        error: "Live updates are stale. Polling fallback is active.",
      });
    }, STALE_AFTER_MS);
  }

  private scheduleReconnect() {
    if (!this.started || this.reconnectTimer !== null) {
      return;
    }
    this.reconnectAttempt += 1;
    const delay =
      RECONNECT_DELAYS_MS[Math.min(this.reconnectAttempt - 1, RECONNECT_DELAYS_MS.length - 1)];
    this.setSocketState({
      status: "reconnecting",
      reconnectAttempt: this.reconnectAttempt,
      error: `Live updates disconnected. Reconnecting in ${Math.round(delay / 1000)}s…`,
    });
    this.reconnectTimer = window.setTimeout(() => {
      this.reconnectTimer = null;
      this.connect();
    }, delay);
  }

  private connect() {
    if (!this.started) {
      return;
    }
    this.intentionalClose = false;
    this.setSocketState({
      status: this.reconnectAttempt > 0 ? "reconnecting" : "connecting",
      reconnectAttempt: this.reconnectAttempt,
      isStale: false,
    });

    const socket = new WebSocket(websocketUrl());
    this.socket = socket;

    socket.addEventListener("open", () => {
      if (!this.started || this.socket !== socket) {
        return;
      }
      const didReconnect = this.hasConnectedOnce || this.reconnectAttempt > 0;
      this.hasConnectedOnce = true;
      this.reconnectAttempt = 0;
      this.setSocketState({
        status: "open",
        reconnectAttempt: 0,
        error: null,
        isStale: false,
      });
      this.markActivity();
      if (this.heartbeatTimer !== null) {
        window.clearInterval(this.heartbeatTimer);
      }
      this.heartbeatTimer = window.setInterval(() => {
        if (this.socket?.readyState === WebSocket.OPEN) {
          try {
            this.socket.send("ping");
          } catch (error) {
            this.setSocketState({
              status: "error",
              error:
                error instanceof Error ? `Heartbeat failed: ${error.message}` : "Heartbeat failed",
            });
          }
        }
      }, HEARTBEAT_MS);
      if (didReconnect) {
        void this.syncSnapshot("Reconnect sync failed");
      }
    });

    socket.addEventListener("message", (event) => {
      if (!this.started || this.socket !== socket) {
        return;
      }
      this.markActivity();
      if (typeof event.data !== "string") {
        this.setSocketState({
          status: "error",
          error: "Received non-text websocket data",
        });
        return;
      }

      const rawPayload = event.data.trim();
      if (!rawPayload) {
        return;
      }

      let payload: WsEnvelope;
      try {
        payload = JSON.parse(rawPayload) as WsEnvelope;
      } catch {
        this.setSocketState({
          status: "error",
          error: `Received malformed websocket data: ${rawPayload.slice(0, 80)}`,
        });
        return;
      }
      if (payload.type === "pong") {
        return;
      }
      this.store().applyEvent(payload);
    });

    socket.addEventListener("error", () => {
      if (!this.started || this.socket !== socket) {
        return;
      }
      this.setSocketState({
        status: "error",
        error: "WebSocket error detected. Reconnecting…",
      });
    });

    socket.addEventListener("close", () => {
      if (this.socket === socket) {
        this.socket = null;
      }
      if (!this.started || this.intentionalClose) {
        return;
      }
      if (this.heartbeatTimer !== null) {
        window.clearInterval(this.heartbeatTimer);
        this.heartbeatTimer = null;
      }
      this.scheduleReconnect();
    });
  }

  private stop() {
    this.started = false;
    this.hasConnectedOnce = false;
    this.reconnectAttempt = 0;
    if (this.releaseTimer !== null) {
      window.clearTimeout(this.releaseTimer);
      this.releaseTimer = null;
    }
    this.clearTimers();
    this.intentionalClose = true;
    if (this.socket && this.socket.readyState < WebSocket.CLOSING) {
      this.socket.close();
    }
    this.socket = null;
    this.setSocketState({
      status: "closed",
      error: null,
      lastMessageAt: null,
      reconnectAttempt: 0,
      isStale: false,
    });
  }

  resetForTests() {
    this.subscribers = 0;
    this.stop();
  }
}

export const liveClient = new LiveClient();

